const embeddedMap = "data:image/png;base64,";

export default function TNInteractiveDistrictMap() {
  const [hovered, setHovered] = useState<ReferenceDistrict | null>(null);
  const [selected, setSelected] = useState<ReferenceDistrict | null>(null);
  const active = selected || hovered;

  const districtCount = useMemo(() => REFERENCE_DISTRICTS.length, []);

  return (
    <div className="w-full min-h-screen bg-slate-950 text-slate-100 p-4 md:p-8">
      <div className="mx-auto max-w-7xl grid gap-4 lg:grid-cols-[1fr_320px]">
        <div className="rounded-2xl bg-white/5 p-3 shadow-2xl ring-1 ring-white/10">
          <div className="mb-3 flex flex-wrap items-center justify-between gap-2 px-1">
            <div>
              <h1 className="text-xl md:text-2xl font-semibold">Tamil Nadu District Interactive Layout</h1>
              <p className="text-sm text-slate-300">Hover or click a district hotspot. Approximate overlay for presentation/prototype use.</p>
            </div>
            <span className="rounded-full bg-slate-800 px-3 py-1 text-sm text-slate-200">{districtCount} districts</span>
          </div>

          <div className="relative w-full overflow-hidden rounded-xl bg-slate-100">
            <svg
              viewBox={`0 0 ${REFERENCE_MAP_WIDTH} ${REFERENCE_MAP_HEIGHT}`}
              role="img"
              aria-label="Interactive Tamil Nadu district layout"
              className="h-auto w-full select-none"
            >
              <image href={embeddedMap} x="0" y="0" width={REFERENCE_MAP_WIDTH} height={REFERENCE_MAP_HEIGHT} preserveAspectRatio="xMidYMid meet" />

              {REFERENCE_DISTRICTS.map((d) => {
                const isActive = active?.id === d.id;
                return (
                  <g key={d.id}>
                    <ellipse
                      cx={d.x}
                      cy={d.y}
                      rx={d.rx}
                      ry={d.ry}
                      fill={isActive ? "rgba(14,165,233,0.35)" : "rgba(14,165,233,0.02)"}
                      stroke={isActive ? "#0ea5e9" : "rgba(15,23,42,0.05)"}
                      strokeWidth={isActive ? 5 : 1}
                      className="cursor-pointer transition-all duration-150"
                      onMouseEnter={() => setHovered(d)}
                      onMouseLeave={() => setHovered(null)}
                      onClick={() => setSelected(d)}
                    >
                      <title>{d.name}</title>
                    </ellipse>
                    {isActive && (
                      <text
                        x={d.x}
                        y={d.y - d.ry - 12}
                        textAnchor="middle"
                        fontSize="28"
                        fontWeight="700"
                        fill="#0f172a"
                        stroke="#ffffff"
                        strokeWidth="6"
                        paintOrder="stroke"
                        pointerEvents="none"
                      >
                        {d.name}
                      </text>
                    )}
                  </g>
                );
              })}
            </svg>
          </div>
        </div>

        <aside className="rounded-2xl bg-white/5 p-5 shadow-2xl ring-1 ring-white/10">
          <h2 className="text-lg font-semibold">District Info</h2>
          <div className="mt-4 rounded-xl bg-slate-900 p-4 ring-1 ring-white/10">
            {active ? (
              <>
                <div className="text-2xl font-bold">{active.name}</div>
                <div className="mt-2 text-sm text-slate-300">Region: {active.region}</div>
                <div className="mt-4 h-2 rounded-full" style={{ backgroundColor: active.fill }} />
                <p className="mt-4 text-sm leading-6 text-slate-300">
                  Use this click event to open district dashboards, project flow trackers, grievance heatmaps, tender intelligence, or fund-flow pages in TN-OSIRIS FlowRadar.
                </p>
              </>
            ) : (
              <p className="text-sm leading-6 text-slate-300">Hover over the map or click a district hotspot to view its name and region.</p>
            )}
          </div>

          <button
            type="button"
            onClick={() => setSelected(null)}
            className="mt-4 w-full rounded-xl bg-sky-500 px-4 py-3 font-medium text-white hover:bg-sky-400"
          >
            Clear selection
          </button>

          <div className="mt-5 text-xs leading-5 text-slate-400">
            Production note: for exact district boundary interactivity, use official Tamil Nadu district GeoJSON polygons and replace the approximate ellipse hotspots.
          </div>
        </aside>
      </div>
    </div>
  );
}
